export function pronunciationClip(wordId, baseUrl = "./src/assets/pronunciation") {
  const match = /^cet6-(\d{3,4})$/u.exec(String(wordId ?? ""));
  if (!match) return null;
  const entry = PRONUNCIATION_CLIPS[Number(match[1]) - 1];
  if (!entry) return null;
  const [chunk, start, length] = entry;
  const version = PRONUNCIATION_CHUNK_HASHES[chunk - 1];
  return { url: `${baseUrl}/chunk-${String(chunk).padStart(3, "0")}.wav?v=${version}`, start, length };
}
